/* =========================================================
   HOUSEKEEPING QR REPORT — DESIGN SYSTEM
   Font: Nunito | Palette: Blue (#4A90FF) + Clean White
   ========================================================= */

/* ---------- RESET & BASE ---------- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
    /* Colors */
    --c-primary:      #4A90FF;
    --c-primary-dark: #2E75E8;
    --c-primary-lite: #E8F4FF;
    --c-bg-start:     #F8F9FB;
    --c-bg-end:       #FFFFFF;
    --c-white:        #FFFFFF;
    --c-text-h:       #111111;
    --c-text-b:       #333333;
    --c-text-cap:     #6B7280;
    --c-border:       #E5E9F0;
    --c-danger:       #FF4D4D;
    --c-success:      #22C55E;
    --c-warn:         #F59E0B;

    /* Radii */
    --r-card-lg:  20px;
    --r-card-md:  16px;
    --r-card-sm:  12px;
    --r-pill:     50px;
    --r-btn:      26px;

    /* Spacing */
    --px: 16px;
    --section-gap: 24px;
    --card-gap: 16px;

    /* Shadow */
    --shadow-card: 0 8px 24px rgba(74,144,255,0.12);
    --shadow-btn:  0 4px 16px rgba(74,144,255,0.35);
    --shadow-sm:   0 2px 8px rgba(0,0,0,0.08);

    /* Typography */
    --ff: 'Nunito', system-ui, sans-serif;
}

html { font-size: 16px; -webkit-text-size-adjust: 100%; }

body {
    font-family: var(--ff);
    background: linear-gradient(160deg, var(--c-bg-start) 0%, var(--c-bg-end) 100%);
    min-height: 100dvh;
    min-height: 100vh;
    color: var(--c-text-b);
    overflow: hidden;
    position: relative;
}

/* ---------- SCREEN SYSTEM ---------- */
.screen {
    position: fixed;
    inset: 0;
    width: 100%;
    height: 100%;
    height: 100dvh;
    overflow: hidden;
    background: linear-gradient(160deg, var(--c-bg-start) 0%, var(--c-bg-end) 100%);
    transform: translateX(100%);
    transition: transform 320ms cubic-bezier(0.4, 0, 0.2, 1);
    z-index: 1;
    will-change: transform;
}

.screen--active {
    transform: translateX(0);
    z-index: 2;
}

.screen--exit {
    transform: translateX(-30%);
    z-index: 1;
    transition: transform 320ms cubic-bezier(0.4, 0, 0.2, 1);
}

.screen__inner {
    height: 100%;
    padding: 0 var(--px);
    padding-top: max(env(safe-area-inset-top), 16px);
    padding-bottom: max(env(safe-area-inset-bottom), 16px);
    display: flex;
    flex-direction: column;
    gap: var(--card-gap);
}

.screen__inner--scrollable {
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    overscroll-behavior: contain;
    padding-bottom: 100px;
}

.screen__inner--center {
    align-items: center;
    justify-content: center;
    text-align: center;
    gap: 20px;
}

/* ---------- TYPOGRAPHY ---------- */
.screen-title {
    font-size: 22px;
    font-weight: 800;
    color: var(--c-text-h);
    line-height: 1.2;
}

.screen-subtitle {
    font-size: 14px;
    color: var(--c-text-cap);
    line-height: 1.6;
    margin-top: 4px;
}

.section-label {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    font-weight: 700;
    color: var(--c-text-h);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    padding: 0 2px;
}

/* ---------- CARDS ---------- */
.card {
    border-radius: var(--r-card-lg);
    padding: 18px;
    transition: transform 150ms ease, box-shadow 150ms ease;
}

.card:active { transform: scale(0.99); }

.card--main {
    background: var(--c-primary-lite);
    box-shadow: var(--shadow-card);
    border: 1px solid rgba(74,144,255,0.12);
}

.card--secondary {
    background: var(--c-white);
    box-shadow: var(--shadow-sm);
    border: 1px solid var(--c-border);
}

/* ---------- BUTTONS ---------- */
.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    width: 100%;
    height: 52px;
    border-radius: var(--r-btn);
    border: none;
    cursor: pointer;
    font-family: var(--ff);
    font-size: 16px;
    font-weight: 700;
    transition: transform 150ms ease, background 150ms ease, box-shadow 150ms ease;
    -webkit-tap-highlight-color: transparent;
    user-select: none;
}

.btn:active { transform: scale(0.97); }

.btn--primary {
    background: var(--c-primary);
    color: var(--c-white);
    box-shadow: var(--shadow-btn);
}

.btn--primary:active { background: var(--c-primary-dark); }

.btn--cta {
    font-size: 17px;
}

.btn-back {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: var(--c-white);
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: var(--shadow-sm);
    color: var(--c-text-h);
    flex-shrink: 0;
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease;
}
.btn-back:active { transform: scale(0.93); }

.btn-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease, background 150ms ease;
    flex-shrink: 0;
}
.btn-icon:active { transform: scale(0.92); }

.btn-icon--ghost {
    background: var(--c-white);
    box-shadow: var(--shadow-sm);
    color: var(--c-text-h);
}

.btn-icon--primary {
    background: var(--c-primary);
    box-shadow: var(--shadow-btn);
    color: white;
}

/* ---------- SCREEN 1: QR SCAN ---------- */
.screen-header {
    padding-top: 8px;
    padding-bottom: 4px;
}

.app-logo {
    display: inline-block;
    margin-bottom: 12px;
}

.qr-card {
    flex: 1;
    min-height: 0;
    border-radius: var(--r-card-lg);
    background: var(--c-text-h);
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-card);
    max-height: 340px;
}

#qr-reader {
    width: 100% !important;
    height: 100% !important;
    min-height: 280px;
}

/* Override html5-qrcode default styles */
#qr-reader > div { border: none !important; }
#qr-reader video {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover !important;
    display: block !important;
}
#qr-reader canvas { display: none !important; }
#qr-reader__scan_region img { display: none !important; }
#qr-reader__dashboard { display: none !important; }

.qr-overlay {
    position: absolute;
    inset: 0;
    pointer-events: none;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0,0,0,0.4);
}

.qr-frame {
    width: 200px;
    height: 200px;
    position: relative;
}

.qr-corner {
    position: absolute;
    width: 30px;
    height: 30px;
    border-color: white;
    border-style: solid;
    border-radius: 4px;
}
.qr-corner--tl { top:0; left:0; border-width: 3px 0 0 3px; border-radius: 6px 0 0 0; }
.qr-corner--tr { top:0; right:0; border-width: 3px 3px 0 0; border-radius: 0 6px 0 0; }
.qr-corner--bl { bottom:0; left:0; border-width: 0 0 3px 3px; border-radius: 0 0 0 6px; }
.qr-corner--br { bottom:0; right:0; border-width: 0 3px 3px 0; border-radius: 0 0 6px 0; }

.qr-scan-line {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, rgba(74,144,255,0.9), transparent);
    animation: scanLine 2s ease-in-out infinite;
    border-radius: 1px;
}

@keyframes scanLine {
    0%   { top: 0; opacity: 1; }
    50%  { top: calc(100% - 2px); opacity: 1; }
    100% { top: 0; opacity: 1; }
}

.qr-hint {
    position: absolute;
    bottom: 12px;
    left: 12px;
    right: 12px;
    background: rgba(0,0,0,0.6);
    border-radius: 10px;
    padding: 8px 12px;
    display: flex;
    align-items: center;
    gap: 8px;
    color: white;
    font-size: 12px;
    font-weight: 600;
    line-height: 1.4;
}

/* Status badge */
.status-badge {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 14px;
    border-radius: var(--r-card-sm);
    font-size: 13px;
    font-weight: 600;
}

.status-badge--info { background: var(--c-primary-lite); color: var(--c-primary); }
.status-badge--success { background: #DCFCE7; color: #16A34A; }
.status-badge--error { background: #FEE2E2; color: #DC2626; }

.status-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: currentColor;
    animation: blink 1.2s ease-in-out infinite;
    flex-shrink: 0;
}

@keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.3; }
}

/* ---------- SCREEN 2: CAMERA ---------- */
.camera-header, .report-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 8px;
}

.camera-instruction {
    font-size: 14px;
    color: var(--c-text-cap);
    font-weight: 600;
}

.room-label-header {
    display: flex;
    align-items: center;
    gap: 6px;
}

.room-label-header__badge {
    font-size: 11px;
    font-weight: 800;
    color: var(--c-primary);
    background: var(--c-primary-lite);
    padding: 2px 8px;
    border-radius: 6px;
    letter-spacing: 0.08em;
}

.room-label-header__number {
    font-size: 22px;
    font-weight: 900;
    color: var(--c-text-h);
    letter-spacing: 0.02em;
}

.camera-card {
    flex: 1;
    min-height: 0;
    max-height: 360px;
    border-radius: var(--r-card-lg);
    overflow: hidden;
    background: var(--c-text-h);
    position: relative;
    box-shadow: var(--shadow-card);
}

.camera-preview {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
}

.camera-overlay-ui {
    position: absolute;
    top: 12px;
    right: 12px;
}

.photo-counter-badge {
    background: rgba(0,0,0,0.6);
    backdrop-filter: blur(4px);
    border-radius: 20px;
    padding: 4px 12px;
    font-size: 15px;
    font-weight: 800;
    color: white;
    display: flex;
    align-items: center;
    gap: 1px;
}

.photo-counter-badge__sep { color: rgba(255,255,255,0.5); margin: 0 1px; }
.photo-counter-badge__max { color: rgba(255,255,255,0.6); }

.camera-controls {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 8px;
}

/* Shutter Button */
.btn-shutter {
    width: 72px;
    height: 72px;
    border-radius: 50%;
    background: none;
    border: none;
    cursor: pointer;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    -webkit-tap-highlight-color: transparent;
    transition: transform 120ms ease;
}

.btn-shutter:active { transform: scale(0.93); }

.btn-shutter__ring {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    border: 3px solid var(--c-primary);
    background: rgba(74,144,255,0.1);
}

.btn-shutter__inner {
    width: 54px;
    height: 54px;
    border-radius: 50%;
    background: var(--c-primary);
    box-shadow: 0 4px 16px rgba(74,144,255,0.4);
    transition: transform 120ms ease, background 120ms ease;
}

.btn-shutter:active .btn-shutter__inner {
    background: var(--c-primary-dark);
    transform: scale(0.93);
}

/* Photo thumbnails */
.photo-thumbnails {
    display: flex;
    gap: 10px;
    overflow-x: auto;
    padding: 4px 0 8px;
    scrollbar-width: none;
    min-height: 76px;
    align-items: center;
}

.photo-thumbnails::-webkit-scrollbar { display: none; }

.thumb-wrap {
    position: relative;
    flex-shrink: 0;
    border-radius: var(--r-card-sm);
    overflow: visible;
    animation: thumbIn 200ms ease;
}

@keyframes thumbIn {
    from { transform: scale(0.7); opacity: 0; }
    to   { transform: scale(1);   opacity: 1; }
}

.thumb-wrap img {
    width: 64px;
    height: 64px;
    object-fit: cover;
    border-radius: var(--r-card-sm);
    display: block;
    border: 2px solid var(--c-white);
    box-shadow: var(--shadow-sm);
}

.thumb-delete {
    position: absolute;
    top: -6px;
    right: -6px;
    width: 22px;
    height: 22px;
    border-radius: 50%;
    background: var(--c-danger);
    border: 2px solid white;
    color: white;
    font-size: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    z-index: 2;
    -webkit-tap-highlight-color: transparent;
    transition: transform 120ms ease;
}

.thumb-delete:active { transform: scale(0.88); }

.thumb-add {
    width: 64px;
    height: 64px;
    border-radius: var(--r-card-sm);
    border: 2px dashed var(--c-primary);
    background: var(--c-primary-lite);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--c-primary);
    font-size: 24px;
    flex-shrink: 0;
    cursor: pointer;
    -webkit-tap-highlight-color: transparent;
    font-weight: 300;
}

/* ---------- SCREEN 3: REPORT ---------- */
.voice-card {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.voice-status-row {
    display: flex;
    align-items: center;
    gap: 10px;
}

.voice-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
    transition: background 200ms ease;
}

.voice-dot--idle     { background: var(--c-border); }
.voice-dot--ready    { background: var(--c-primary); animation: blink 1.5s infinite; }
.voice-dot--rec      { background: var(--c-danger); animation: blink 0.7s infinite; }
.voice-dot--done     { background: var(--c-success); animation: none; }

.voice-status-label {
    font-size: 13px;
    font-weight: 600;
    color: var(--c-text-cap);
}

.voice-btn-wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
}

/* Mic button */
.btn-mic {
    width: 88px;
    height: 88px;
    border-radius: 50%;
    background: var(--c-primary);
    border: none;
    cursor: pointer;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 8px 28px rgba(74,144,255,0.4);
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease, background 150ms ease, box-shadow 150ms ease;
}

.btn-mic:active {
    transform: scale(0.94);
    box-shadow: 0 4px 14px rgba(74,144,255,0.3);
}

.btn-mic--recording {
    background: var(--c-danger) !important;
    box-shadow: 0 8px 28px rgba(255,77,77,0.4) !important;
    animation: micPulse 1s ease-in-out infinite;
}

.btn-mic__ripple {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    background: rgba(74,144,255,0.25);
    transform: scale(1);
    opacity: 0;
}

.btn-mic--recording .btn-mic__ripple {
    animation: ripple 1.2s ease-out infinite;
}

@keyframes micPulse {
    0%, 100% { transform: scale(1); }
    50%       { transform: scale(1.04); }
}

@keyframes ripple {
    0%   { transform: scale(1);    opacity: 0.7; }
    100% { transform: scale(1.55); opacity: 0;   }
}

.voice-timer {
    font-size: 15px;
    font-weight: 700;
    color: var(--c-danger);
    letter-spacing: 0.04em;
}

.voice-transcript-wrap {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.transcript-label {
    font-size: 12px;
    font-weight: 700;
    color: var(--c-text-cap);
    text-transform: uppercase;
    letter-spacing: 0.06em;
}

.voice-transcript, .note-input {
    width: 100%;
    border: 1.5px solid var(--c-border);
    border-radius: var(--r-card-md);
    padding: 12px 14px;
    font-family: var(--ff);
    font-size: 15px;
    font-weight: 600;
    color: var(--c-text-b);
    line-height: 1.6;
    resize: none;
    background: var(--c-white);
    outline: none;
    transition: border-color 200ms ease;
}

.voice-transcript:focus, .note-input:focus {
    border-color: var(--c-primary);
    box-shadow: 0 0 0 3px rgba(74,144,255,0.12);
}

.voice-transcript::placeholder, .note-input::placeholder {
    color: #B0B8C1;
    font-weight: 400;
}

/* Report photos */
.report-photo-scroll {
    display: flex;
    gap: 10px;
    overflow-x: auto;
    scrollbar-width: none;
    padding: 2px 0;
    min-height: 80px;
    align-items: center;
}

.report-photo-scroll::-webkit-scrollbar { display: none; }

.report-photo-thumb {
    flex-shrink: 0;
    width: 72px;
    height: 72px;
    border-radius: var(--r-card-md);
    object-fit: cover;
    border: 2px solid rgba(74,144,255,0.2);
    box-shadow: var(--shadow-sm);
    animation: thumbIn 200ms ease;
}

/* Sticky CTA */
.sticky-cta {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 12px var(--px) max(env(safe-area-inset-bottom), 16px);
    background: linear-gradient(to top, rgba(248,249,251,1) 60%, rgba(248,249,251,0));
    z-index: 10;
}

/* ---------- SCREEN 4: SUCCESS ---------- */
.success-anim {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 8px;
}

.success-circle {
    width: 100px;
    height: 100px;
    position: relative;
    z-index: 2;
    animation: successPop 500ms cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

@keyframes successPop {
    0%   { transform: scale(0.5); opacity: 0; }
    100% { transform: scale(1);   opacity: 1; }
}

.success-check {
    width: 100px;
    height: 100px;
}

.checkmark {
    stroke-dasharray: 40;
    stroke-dashoffset: 40;
    animation: drawCheck 500ms ease 400ms forwards;
}

@keyframes drawCheck {
    to { stroke-dashoffset: 0; }
}

.success-rings {
    position: absolute;
    display: flex;
    align-items: center;
    justify-content: center;
}

.success-ring {
    position: absolute;
    border-radius: 50%;
    border: 2px solid rgba(74,144,255,0.2);
    animation: ringExpand 2s ease-out infinite;
}

.success-ring--1 { width: 120px; height: 120px; animation-delay: 0.5s; }
.success-ring--2 { width: 150px; height: 150px; animation-delay: 1s; }

@keyframes ringExpand {
    0%   { transform: scale(0.8); opacity: 0.7; }
    100% { transform: scale(1.4); opacity: 0; }
}

.success-title {
    font-size: 26px;
    font-weight: 900;
    color: var(--c-text-h);
    line-height: 1.3;
}

.success-subtitle {
    font-size: 15px;
    color: var(--c-text-cap);
    font-weight: 600;
}

.success-meta {
    display: flex;
    gap: 12px;
    background: var(--c-primary-lite);
    border-radius: var(--r-card-md);
    padding: 14px 16px;
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
}

.success-meta__item {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    font-weight: 700;
    color: var(--c-primary);
}

.success-countdown {
    font-size: 13px;
    color: var(--c-text-cap);
    font-weight: 600;
}

/* ---------- TOAST ---------- */
.toast {
    position: fixed;
    bottom: 100px;
    left: var(--px);
    right: var(--px);
    padding: 14px 18px;
    border-radius: var(--r-card-md);
    font-size: 14px;
    font-weight: 700;
    color: white;
    text-align: center;
    z-index: 9999;
    pointer-events: none;
    transform: translateY(20px);
    opacity: 0;
    transition: transform 250ms ease, opacity 250ms ease;
    box-shadow: 0 8px 24px rgba(0,0,0,0.18);
}

.toast--visible {
    transform: translateY(0);
    opacity: 1;
}

.toast--error   { background: var(--c-danger); }
.toast--success { background: var(--c-success); }
.toast--info    { background: var(--c-primary); }
.toast--warn    { background: var(--c-warn); }

/* ---------- LOADING OVERLAY ---------- */
.loading-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.45);
    backdrop-filter: blur(4px);
    z-index: 99999;
    display: flex;
    align-items: center;
    justify-content: center;
}

.loading-card {
    background: white;
    border-radius: var(--r-card-lg);
    padding: 32px 40px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
    box-shadow: 0 16px 40px rgba(0,0,0,0.2);
    min-width: 160px;
}

.loading-spinner {
    width: 40px;
    height: 40px;
    border: 3px solid var(--c-primary-lite);
    border-top-color: var(--c-primary);
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

.loading-text {
    font-size: 14px;
    font-weight: 700;
    color: var(--c-text-cap);
}

/* ---------- EMPTY STATE INLINE ---------- */
.empty-state-inline {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 76px;
    width: 100%;
    font-size: 13px;
    font-weight: 600;
    color: var(--c-text-cap);
}

/* ---------- MEDIA (LARGER PHONES) ---------- */
@media (min-height: 750px) {
    .qr-card { max-height: 400px; }
    .camera-card { max-height: 440px; }
}

@media (min-width: 480px) {
    :root { --px: 24px; }
    .screen { max-width: 480px; margin: 0 auto; }
    body { display: flex; justify-content: center; }
}

/* =========================================================
   HOUSEKEEPING QR REPORT — DESIGN SYSTEM
   Font: Nunito | Palette: Blue (#4A90FF) + Clean White
   ========================================================= */

/* ---------- RESET & BASE ---------- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
    /* Colors */
    --c-primary:      #4A90FF;
    --c-primary-dark: #2E75E8;
    --c-primary-lite: #E8F4FF;
    --c-bg-start:     #F8F9FB;
    --c-bg-end:       #FFFFFF;
    --c-white:        #FFFFFF;
    --c-text-h:       #111111;
    --c-text-b:       #333333;
    --c-text-cap:     #6B7280;
    --c-border:       #E5E9F0;
    --c-danger:       #FF4D4D;
    --c-success:      #22C55E;
    --c-warn:         #F59E0B;

    /* Radii */
    --r-card-lg:  20px;
    --r-card-md:  16px;
    --r-card-sm:  12px;
    --r-pill:     50px;
    --r-btn:      26px;

    /* Spacing */
    --px: 16px;
    --section-gap: 24px;
    --card-gap: 16px;

    /* Shadow */
    --shadow-card: 0 8px 24px rgba(74,144,255,0.12);
    --shadow-btn:  0 4px 16px rgba(74,144,255,0.35);
    --shadow-sm:   0 2px 8px rgba(0,0,0,0.08);

    /* Typography */
    --ff: 'Nunito', system-ui, sans-serif;
}

html { font-size: 16px; -webkit-text-size-adjust: 100%; }

body {
    font-family: var(--ff);
    background: linear-gradient(160deg, var(--c-bg-start) 0%, var(--c-bg-end) 100%);
    min-height: 100dvh;
    min-height: 100vh;
    color: var(--c-text-b);
    overflow: hidden;
    position: relative;
}

/* ---------- SCREEN SYSTEM ---------- */
.screen {
    position: fixed;
    inset: 0;
    width: 100%;
    height: 100%;
    height: 100dvh;
    overflow: hidden;
    background: linear-gradient(160deg, var(--c-bg-start) 0%, var(--c-bg-end) 100%);
    transform: translateX(100%);
    transition: transform 320ms cubic-bezier(0.4, 0, 0.2, 1);
    z-index: 1;
    will-change: transform;
}

.screen--active {
    transform: translateX(0);
    z-index: 2;
}

.screen--exit {
    transform: translateX(-30%);
    z-index: 1;
    transition: transform 320ms cubic-bezier(0.4, 0, 0.2, 1);
}

.screen__inner {
    height: 100%;
    padding: 0 var(--px);
    padding-top: max(env(safe-area-inset-top), 16px);
    padding-bottom: max(env(safe-area-inset-bottom), 16px);
    display: flex;
    flex-direction: column;
    gap: var(--card-gap);
}

.screen__inner--scrollable {
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    overscroll-behavior: contain;
    padding-bottom: 100px;
}

.screen__inner--center {
    align-items: center;
    justify-content: center;
    text-align: center;
    gap: 20px;
}

/* ---------- TYPOGRAPHY ---------- */
.screen-title {
    font-size: 22px;
    font-weight: 800;
    color: var(--c-text-h);
    line-height: 1.2;
}

.screen-subtitle {
    font-size: 14px;
    color: var(--c-text-cap);
    line-height: 1.6;
    margin-top: 4px;
}

.section-label {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    font-weight: 700;
    color: var(--c-text-h);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    padding: 0 2px;
    margin-top: 6px;
}

/* ---------- CARDS ---------- */
.card {
    border-radius: var(--r-card-lg);
    padding: 18px;
    transition: transform 150ms ease, box-shadow 150ms ease;
}

.card:active { transform: scale(0.99); }

.card--main {
    background: var(--c-primary-lite);
    box-shadow: var(--shadow-card);
    border: 1px solid rgba(74,144,255,0.12);
}

.card--secondary {
    background: var(--c-white);
    box-shadow: var(--shadow-sm);
    border: 1px solid var(--c-border);
}

/* ---------- BUTTONS ---------- */
.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    width: 100%;
    height: 52px;
    border-radius: var(--r-btn);
    border: none;
    cursor: pointer;
    font-family: var(--ff);
    font-size: 16px;
    font-weight: 700;
    transition: transform 150ms ease, background 150ms ease, box-shadow 150ms ease;
    -webkit-tap-highlight-color: transparent;
    user-select: none;
}

.btn:active { transform: scale(0.97); }

.btn--primary {
    background: var(--c-primary);
    color: var(--c-white);
    box-shadow: var(--shadow-btn);
}

.btn--primary:active { background: var(--c-primary-dark); }

.btn--cta { font-size: 17px; }

.btn-back {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: var(--c-white);
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: var(--shadow-sm);
    color: var(--c-text-h);
    flex-shrink: 0;
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease;
}
.btn-back:active { transform: scale(0.93); }

.btn-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease, background 150ms ease;
    flex-shrink: 0;
}
.btn-icon:active { transform: scale(0.92); }

.btn-icon--ghost {
    background: var(--c-white);
    box-shadow: var(--shadow-sm);
    color: var(--c-text-h);
}

.btn-icon--primary {
    background: var(--c-primary);
    box-shadow: var(--shadow-btn);
    color: white;
}

/* ---------- SCREEN 1: QR SCAN ---------- */
.screen-header {
    padding-top: 8px;
    padding-bottom: 4px;
}

.app-logo { display: inline-block; margin-bottom: 12px; }

.qr-card {
    flex: 1;
    min-height: 0;
    border-radius: var(--r-card-lg);
    background: #1a1a2e;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-card);
    max-height: 340px;
}

#qr-reader {
    width: 100% !important;
    height: 100% !important;
    min-height: 280px;
}

/* Override html5-qrcode default styles */
#qr-reader > div { border: none !important; }
#qr-reader video {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover !important;
    display: block !important;
    border: none !important;
}
#qr-reader__scan_region img { display: none !important; }
#qr-reader__dashboard { display: none !important; }
#qr-reader__status_span { display: none !important; }

.qr-overlay {
    position: absolute;
    inset: 0;
    pointer-events: none;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0,0,0,0.45);
}

.qr-frame {
    width: 200px;
    height: 200px;
    position: relative;
}

.qr-corner {
    position: absolute;
    width: 30px;
    height: 30px;
    border-color: white;
    border-style: solid;
}
.qr-corner--tl { top:0; left:0; border-width: 3px 0 0 3px; border-radius: 6px 0 0 0; }
.qr-corner--tr { top:0; right:0; border-width: 3px 3px 0 0; border-radius: 0 6px 0 0; }
.qr-corner--bl { bottom:0; left:0; border-width: 0 0 3px 3px; border-radius: 0 0 0 6px; }
.qr-corner--br { bottom:0; right:0; border-width: 0 3px 3px 0; border-radius: 0 0 6px 0; }

.qr-scan-line {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, rgba(74,144,255,0.95), transparent);
    animation: scanLine 2s ease-in-out infinite;
    border-radius: 1px;
}

@keyframes scanLine {
    0%   { top: 0; opacity: 1; }
    50%  { top: calc(100% - 2px); opacity: 1; }
    100% { top: 0; opacity: 1; }
}

.qr-hint {
    position: absolute;
    bottom: 12px; left: 12px; right: 12px;
    background: rgba(0,0,0,0.65);
    border-radius: 10px;
    padding: 8px 12px;
    display: flex;
    align-items: center;
    gap: 8px;
    color: white;
    font-size: 12px;
    font-weight: 600;
    line-height: 1.4;
}

/* Status badge */
.status-badge {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 14px;
    border-radius: var(--r-card-sm);
    font-size: 13px;
    font-weight: 600;
}

.status-badge--info    { background: var(--c-primary-lite); color: var(--c-primary); }
.status-badge--success { background: #DCFCE7; color: #16A34A; }
.status-badge--error   { background: #FEE2E2; color: #DC2626; }

.status-dot {
    width: 8px; height: 8px;
    border-radius: 50%;
    background: currentColor;
    animation: blink 1.2s ease-in-out infinite;
    flex-shrink: 0;
}

@keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.3; }
}

/* ---------- SCREEN 2: CAMERA ---------- */
.camera-header, .report-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 8px;
}

.camera-instruction {
    font-size: 14px;
    color: var(--c-text-cap);
    font-weight: 600;
    margin-top: -4px;
}

.room-label-header {
    display: flex;
    align-items: center;
    gap: 6px;
}

.room-label-header__badge {
    font-size: 11px;
    font-weight: 800;
    color: var(--c-primary);
    background: var(--c-primary-lite);
    padding: 2px 8px;
    border-radius: 6px;
    letter-spacing: 0.08em;
}

.room-label-header__number {
    font-size: 22px;
    font-weight: 900;
    color: var(--c-text-h);
    letter-spacing: 0.02em;
}

.camera-card {
    flex: 1;
    min-height: 0;
    max-height: 360px;
    border-radius: var(--r-card-lg);
    overflow: hidden;
    background: #1a1a2e;
    position: relative;
    box-shadow: var(--shadow-card);
}

.camera-preview {
    width: 100%; height: 100%;
    object-fit: cover;
    display: block;
}

.camera-overlay-ui {
    position: absolute;
    top: 12px; right: 12px;
}

.photo-counter-badge {
    background: rgba(0,0,0,0.6);
    backdrop-filter: blur(4px);
    border-radius: 20px;
    padding: 4px 12px;
    font-size: 15px;
    font-weight: 800;
    color: white;
    display: flex;
    align-items: center;
    gap: 1px;
}

.photo-counter-badge__sep { color: rgba(255,255,255,0.5); margin: 0 1px; }
.photo-counter-badge__max { color: rgba(255,255,255,0.6); }

.camera-controls {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 8px;
}

/* Shutter Button */
.btn-shutter {
    width: 72px; height: 72px;
    border-radius: 50%;
    background: none; border: none;
    cursor: pointer;
    position: relative;
    display: flex; align-items: center; justify-content: center;
    -webkit-tap-highlight-color: transparent;
    transition: transform 120ms ease;
}
.btn-shutter:active { transform: scale(0.93); }

.btn-shutter__ring {
    position: absolute; inset: 0;
    border-radius: 50%;
    border: 3px solid var(--c-primary);
    background: rgba(74,144,255,0.08);
}

.btn-shutter__inner {
    width: 54px; height: 54px;
    border-radius: 50%;
    background: var(--c-primary);
    box-shadow: 0 4px 16px rgba(74,144,255,0.4);
    transition: transform 120ms ease, background 120ms ease;
}

.btn-shutter:active .btn-shutter__inner {
    background: var(--c-primary-dark);
    transform: scale(0.93);
}

/* Photo thumbnails */
.photo-thumbnails {
    display: flex;
    gap: 10px;
    overflow-x: auto;
    padding: 4px 0 8px;
    scrollbar-width: none;
    min-height: 76px;
    align-items: center;
}
.photo-thumbnails::-webkit-scrollbar { display: none; }

.thumb-wrap {
    position: relative;
    flex-shrink: 0;
    animation: thumbIn 200ms ease;
}

@keyframes thumbIn {
    from { transform: scale(0.7); opacity: 0; }
    to   { transform: scale(1);   opacity: 1; }
}

.thumb-wrap img {
    width: 64px; height: 64px;
    object-fit: cover;
    border-radius: var(--r-card-sm);
    display: block;
    border: 2px solid var(--c-white);
    box-shadow: var(--shadow-sm);
}

.thumb-delete {
    position: absolute;
    top: -6px; right: -6px;
    width: 22px; height: 22px;
    border-radius: 50%;
    background: var(--c-danger);
    border: 2px solid white;
    color: white; font-size: 11px;
    display: flex; align-items: center; justify-content: center;
    cursor: pointer; z-index: 2;
    -webkit-tap-highlight-color: transparent;
    transition: transform 120ms ease;
    line-height: 1;
}
.thumb-delete:active { transform: scale(0.88); }

/* ---------- SCREEN 3: REPORT ---------- */
.voice-card {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.voice-status-row {
    display: flex;
    align-items: center;
    gap: 10px;
}

.voice-dot {
    width: 10px; height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
    transition: background 200ms ease;
}
.voice-dot--idle  { background: var(--c-border); }
.voice-dot--ready { background: var(--c-primary); animation: blink 1.5s infinite; }
.voice-dot--rec   { background: var(--c-danger);  animation: blink 0.7s infinite; }
.voice-dot--done  { background: var(--c-success); animation: none; }

.voice-status-label {
    font-size: 13px;
    font-weight: 600;
    color: var(--c-text-cap);
    line-height: 1.4;
}

.voice-btn-wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
}

/* Mic button */
.btn-mic {
    width: 88px; height: 88px;
    border-radius: 50%;
    background: var(--c-primary);
    border: none; cursor: pointer;
    position: relative;
    display: flex; align-items: center; justify-content: center;
    box-shadow: 0 8px 28px rgba(74,144,255,0.4);
    -webkit-tap-highlight-color: transparent;
    transition: transform 150ms ease, background 150ms ease, box-shadow 150ms ease;
}
.btn-mic:active {
    transform: scale(0.94);
    box-shadow: 0 4px 14px rgba(74,144,255,0.3);
}

.btn-mic--recording {
    background: var(--c-danger) !important;
    box-shadow: 0 8px 28px rgba(255,77,77,0.4) !important;
    animation: micPulse 1s ease-in-out infinite;
}

.btn-mic__ripple {
    position: absolute; inset: 0;
    border-radius: 50%;
    background: rgba(255,77,77,0.25);
    transform: scale(1); opacity: 0;
}

.btn-mic--recording .btn-mic__ripple {
    animation: ripple 1.2s ease-out infinite;
}

@keyframes micPulse {
    0%, 100% { transform: scale(1); }
    50%       { transform: scale(1.04); }
}

@keyframes ripple {
    0%   { transform: scale(1);    opacity: 0.7; }
    100% { transform: scale(1.55); opacity: 0;   }
}

.voice-timer {
    font-size: 15px;
    font-weight: 700;
    color: var(--c-danger);
    letter-spacing: 0.04em;
}

.voice-transcript-wrap {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.transcript-label {
    font-size: 12px;
    font-weight: 700;
    color: var(--c-text-cap);
    text-transform: uppercase;
    letter-spacing: 0.06em;
}

.voice-transcript, .note-input {
    width: 100%;
    border: 1.5px solid var(--c-border);
    border-radius: var(--r-card-md);
    padding: 12px 14px;
    font-family: var(--ff);
    font-size: 15px;
    font-weight: 600;
    color: var(--c-text-b);
    line-height: 1.6;
    resize: none;
    background: var(--c-white);
    outline: none;
    transition: border-color 200ms ease, box-shadow 200ms ease;
}

.voice-transcript:focus, .note-input:focus {
    border-color: var(--c-primary);
    box-shadow: 0 0 0 3px rgba(74,144,255,0.12);
}

.voice-transcript::placeholder, .note-input::placeholder {
    color: #B0B8C1;
    font-weight: 400;
}

/* Report photos */
.report-photo-scroll {
    display: flex;
    gap: 10px;
    overflow-x: auto;
    scrollbar-width: none;
    padding: 2px 0;
    min-height: 80px;
    align-items: center;
}
.report-photo-scroll::-webkit-scrollbar { display: none; }

.report-photo-thumb {
    flex-shrink: 0;
    width: 72px; height: 72px;
    border-radius: var(--r-card-md);
    object-fit: cover;
    border: 2px solid rgba(74,144,255,0.2);
    box-shadow: var(--shadow-sm);
    animation: thumbIn 200ms ease;
}

/* Sticky CTA */
.sticky-cta {
    position: fixed;
    bottom: 0; left: 0; right: 0;
    padding: 12px var(--px) max(env(safe-area-inset-bottom), 16px);
    background: linear-gradient(to top, rgba(248,249,251,1) 60%, rgba(248,249,251,0));
    z-index: 10;
}

/* ---------- SCREEN 4: SUCCESS ---------- */
.success-anim {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 8px;
}

.success-circle {
    width: 100px; height: 100px;
    position: relative; z-index: 2;
    animation: successPop 500ms cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

@keyframes successPop {
    0%   { transform: scale(0.5); opacity: 0; }
    100% { transform: scale(1);   opacity: 1; }
}

.success-check { width: 100px; height: 100px; }

.checkmark {
    stroke-dasharray: 40;
    stroke-dashoffset: 40;
    animation: drawCheck 500ms ease 400ms forwards;
}
@keyframes drawCheck { to { stroke-dashoffset: 0; } }

.success-rings {
    position: absolute;
    display: flex; align-items: center; justify-content: center;
}

.success-ring {
    position: absolute;
    border-radius: 50%;
    border: 2px solid rgba(74,144,255,0.2);
    animation: ringExpand 2.5s ease-out infinite;
}
.success-ring--1 { width: 120px; height: 120px; animation-delay: 0.5s; }
.success-ring--2 { width: 150px; height: 150px; animation-delay: 1.2s; }

@keyframes ringExpand {
    0%   { transform: scale(0.8); opacity: 0.6; }
    100% { transform: scale(1.5); opacity: 0;   }
}

.success-title {
    font-size: 26px;
    font-weight: 900;
    color: var(--c-text-h);
    line-height: 1.3;
}

.success-subtitle {
    font-size: 15px;
    color: var(--c-text-cap);
    font-weight: 600;
}

.success-meta {
    display: flex;
    gap: 12px;
    background: var(--c-primary-lite);
    border-radius: var(--r-card-md);
    padding: 14px 16px;
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
}

.success-meta__item {
    display: flex; align-items: center; gap: 6px;
    font-size: 13px; font-weight: 700;
    color: var(--c-primary);
}

.success-countdown {
    font-size: 13px;
    color: var(--c-text-cap);
    font-weight: 600;
}

/* ---------- TOAST ---------- */
.toast {
    position: fixed;
    bottom: 100px;
    left: var(--px); right: var(--px);
    padding: 14px 18px;
    border-radius: var(--r-card-md);
    font-size: 14px; font-weight: 700;
    color: white;
    text-align: center;
    z-index: 9999;
    pointer-events: none;
    transform: translateY(20px); opacity: 0;
    transition: transform 250ms ease, opacity 250ms ease;
    box-shadow: 0 8px 24px rgba(0,0,0,0.18);
}
.toast--visible   { transform: translateY(0); opacity: 1; }
.toast--error     { background: var(--c-danger); }
.toast--success   { background: var(--c-success); }
.toast--info      { background: var(--c-primary); }
.toast--warn      { background: var(--c-warn); }

/* ---------- LOADING OVERLAY ---------- */
.loading-overlay {
    position: fixed; inset: 0;
    background: rgba(0,0,0,0.45);
    backdrop-filter: blur(4px);
    z-index: 99999;
    display: flex; align-items: center; justify-content: center;
}

.loading-card {
    background: white;
    border-radius: var(--r-card-lg);
    padding: 32px 40px;
    display: flex; flex-direction: column;
    align-items: center; gap: 16px;
    box-shadow: 0 16px 40px rgba(0,0,0,0.2);
    min-width: 160px;
}

.loading-spinner {
    width: 40px; height: 40px;
    border: 3px solid var(--c-primary-lite);
    border-top-color: var(--c-primary);
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.loading-text {
    font-size: 14px; font-weight: 700;
    color: var(--c-text-cap);
}

/* ---------- EMPTY STATE ---------- */
.empty-state-inline {
    display: flex; align-items: center; justify-content: center;
    height: 76px; width: 100%;
    font-size: 13px; font-weight: 600;
    color: var(--c-text-cap);
}

/* ---------- RESPONSIVE ---------- */
@media (min-height: 750px) {
    .qr-card    { max-height: 420px; }
    .camera-card { max-height: 440px; }
}

@media (min-width: 480px) {
    :root { --px: 24px; }
    .screen { max-width: 480px; left: 50%; right: auto; transform: translateX(calc(50vw - 50% + 100vw)); }
    .screen--active { transform: translateX(calc(50vw - 50%)); }
    .screen--exit   { transform: translateX(calc(50vw - 50% - 30%)); }
    .sticky-cta, .toast { max-width: 480px; left: 50%; transform: translateX(-50%); right: auto; }
    .toast--visible { transform: translateX(-50%) translateY(0); }
}

