/**
 * Housekeeping QR Report — Main Application
 * Flow: QR Scan → Camera Capture → Room Report → Success
 */

// ─── App State ────────────────────────────────────────────────────────────────
const appState = {
    roomId: null,
    photos: [],        // [{blob, localUrl, s3Url}]
    voiceText: '',
    isRecording: false,
    recognition: null,
    recordTimer: null,
    recordSeconds: 0,
    countdownTimer: null,
    cameraStream: null,
    facingMode: 'environment',
    qrScanner: null,
    qrStarted: false,
};

// ─── Utilities ────────────────────────────────────────────────────────────────
function escapeHtml(text) {
    const d = document.createElement('div');
    d.textContent = String(text ?? '');
    return d.innerHTML;
}

let toastTimer = null;
function showToast(message, type = 'info', duration = 3000) {
    const toast = document.getElementById('toast');
    toast.textContent = message;
    toast.className = `toast toast--${type} toast--visible`;
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => {
        toast.classList.remove('toast--visible');
    }, duration);
}

function showLoading(text = 'Đang xử lý...') {
    document.getElementById('loading-text').textContent = text;
    document.getElementById('loading-overlay').style.display = 'flex';
}

function hideLoading() {
    document.getElementById('loading-overlay').style.display = 'none';
}

// ─── Screen Navigation ────────────────────────────────────────────────────────
const SCREENS = ['screen-qr', 'screen-camera', 'screen-report', 'screen-success'];

function navigateTo(targetId) {
    const current = document.querySelector('.screen--active');
    const target  = document.getElementById(targetId);
    if (!target || current === target) return;

    current.classList.add('screen--exit');
    current.classList.remove('screen--active');
    target.classList.add('screen--active');
    target.style.transform = ''; // reset any inline

    setTimeout(() => {
        current.classList.remove('screen--exit');
    }, 360);
}

function navigateBack(targetId) {
    const current = document.querySelector('.screen--active');
    const target  = document.getElementById(targetId);
    if (!target || current === target) return;

    // Reverse animation
    current.style.transform = 'translateX(100%)';
    current.style.transition = 'transform 280ms cubic-bezier(0.4,0,0.2,1)';
    target.classList.remove('screen--exit');
    target.classList.add('screen--active');
    target.style.transform = 'translateX(-30%)';
    target.style.transition = 'transform 280ms cubic-bezier(0.4,0,0.2,1)';

    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            target.style.transform = 'translateX(0)';
            current.style.transform = 'translateX(100%)';
        });
    });

    setTimeout(() => {
        current.classList.remove('screen--active');
        current.style.transform = '';
        current.style.transition = '';
        target.style.transform = '';
        target.style.transition = '';
    }, 310);
}

// ─── SCREEN 1: QR SCAN ───────────────────────────────────────────────────────
function initQRScreen() {
    document.getElementById('btn-start-scan').addEventListener('click', startQRScanner);
}

async function startQRScanner() {
    if (appState.qrStarted) return;

    const statusEl = document.getElementById('qr-status');
    const statusText = document.getElementById('qr-status-text');
    statusEl.style.display = 'flex';
    statusEl.className = 'status-badge status-badge--info';
    statusText.textContent = 'Đang khởi động camera...';

    try {
        if (appState.qrScanner) {
            try { await appState.qrScanner.stop(); } catch(e) {}
            appState.qrScanner = null;
        }

        const html5QrCode = new Html5Qrcode('qr-reader');
        appState.qrScanner = html5QrCode;

        await html5QrCode.start(
            { facingMode: 'environment' },
            { fps: 10, qrbox: { width: 200, height: 200 }, aspectRatio: 1.333 },
            (decodedText) => onQRDetected(decodedText),
            (errorMessage) => { /* silent scan errors */ }
        );

        appState.qrStarted = true;
        statusText.textContent = 'Camera đang hoạt động — hướng vào mã QR';

    } catch (err) {
        console.error('QR Error:', err);
        statusEl.className = 'status-badge status-badge--error';
        statusText.textContent = 'Không thể khởi động camera. Kiểm tra quyền truy cập.';
        showToast('Không thể mở camera. Cho phép quyền camera nhé!', 'error');
    }
}

async function onQRDetected(decodedText) {
    if (!appState.qrStarted) return;
    appState.qrStarted = false;

    // Stop QR scanner
    try {
        await appState.qrScanner.stop();
    } catch(e) {}

    const roomId = decodedText.trim();
    appState.roomId = roomId;
    appState.photos = [];

    showToast(`Phòng ${roomId} đã nhận diện!`, 'success', 2000);

    // Navigate to camera
    setTimeout(() => {
        openCameraScreen(roomId);
    }, 400);
}

// ─── SCREEN 2: CAMERA CAPTURE ────────────────────────────────────────────────
function initCameraScreen() {
    document.getElementById('btn-camera-back').addEventListener('click', async () => {
        await stopCameraStream();
        // Reset QR screen
        appState.qrStarted = false;
        const statusEl = document.getElementById('qr-status');
        statusEl.style.display = 'none';
        navigateBack('screen-qr');
        // Restart QR after short delay
        setTimeout(startQRScanner, 500);
    });

    document.getElementById('btn-shutter').addEventListener('click', capturePhoto);

    document.getElementById('btn-switch-camera').addEventListener('click', async () => {
        appState.facingMode = appState.facingMode === 'environment' ? 'user' : 'environment';
        await stopCameraStream();
        await startCameraStream();
    });

    document.getElementById('btn-camera-next').addEventListener('click', () => {
        goToReportScreen();
    });
}

async function openCameraScreen(roomId) {
    document.getElementById('camera-room-id').textContent = roomId;
    appState.photos = [];
    updatePhotoUI();
    navigateTo('screen-camera');
    await startCameraStream();
}

async function startCameraStream() {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: appState.facingMode, width: { ideal: 1280 }, height: { ideal: 720 } },
            audio: false,
        });
        appState.cameraStream = stream;
        const video = document.getElementById('camera-preview');
        video.srcObject = stream;
    } catch (err) {
        showToast('Không thể mở camera chụp ảnh', 'error');
        console.error('Camera error:', err);
    }
}

async function stopCameraStream() {
    if (appState.cameraStream) {
        appState.cameraStream.getTracks().forEach(t => t.stop());
        appState.cameraStream = null;
        document.getElementById('camera-preview').srcObject = null;
    }
}

async function capturePhoto() {
    if (appState.photos.length >= 3) {
        showToast('Tối đa 3 ảnh', 'warn');
        return;
    }

    const video  = document.getElementById('camera-preview');
    const canvas = document.getElementById('camera-canvas');
    canvas.width  = video.videoWidth  || 640;
    canvas.height = video.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    // Flash effect
    const flashDiv = document.createElement('div');
    flashDiv.style.cssText = 'position:absolute;inset:0;background:white;opacity:0.7;border-radius:20px;pointer-events:none;animation:none;z-index:10;';
    const cameraCard = document.querySelector('.camera-card');
    cameraCard.appendChild(flashDiv);
    setTimeout(() => flashDiv.remove(), 200);

    canvas.toBlob((blob) => {
        const localUrl = URL.createObjectURL(blob);
        appState.photos.push({ blob, localUrl, s3Url: null });
        updatePhotoUI();

        if (appState.photos.length === 3) {
            setTimeout(() => goToReportScreen(), 600);
        }
    }, 'image/jpeg', 0.85);
}

function updatePhotoUI() {
    const count = appState.photos.length;
    document.getElementById('photo-count').textContent = count;

    // Thumbnails
    const container = document.getElementById('photo-thumbnails');
    container.innerHTML = appState.photos.map((p, i) => `
        <div class="thumb-wrap" data-index="${i}">
            <img src="${escapeHtml(p.localUrl)}" alt="Ảnh ${i+1}">
            <button class="thumb-delete" data-index="${i}" aria-label="Xóa ảnh">✕</button>
        </div>
    `).join('');

    // Delete handlers
    container.querySelectorAll('.thumb-delete').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const idx = parseInt(btn.dataset.index);
            URL.revokeObjectURL(appState.photos[idx].localUrl);
            appState.photos.splice(idx, 1);
            updatePhotoUI();
        });
    });

    // Next button visibility
    const nextBtn = document.getElementById('btn-camera-next');
    const placeholder = document.getElementById('btn-camera-next-placeholder');
    if (count >= 1) {
        nextBtn.style.display = 'flex';
        placeholder.style.display = 'none';
    } else {
        nextBtn.style.display = 'none';
        placeholder.style.display = 'block';
    }
}

function goToReportScreen() {
    if (appState.photos.length === 0) {
        showToast('Chụp ít nhất 1 ảnh trước!', 'warn');
        return;
    }
    stopCameraStream();
    buildReportScreen();
    navigateTo('screen-report');
}

// ─── SCREEN 3: ROOM REPORT ────────────────────────────────────────────────────
function initReportScreen() {
    document.getElementById('btn-report-back').addEventListener('click', async () => {
        stopVoiceRecording();
        navigateBack('screen-camera');
        await startCameraStream();
    });

    document.getElementById('btn-mic').addEventListener('click', toggleVoiceRecording);
    document.getElementById('btn-submit').addEventListener('click', submitReport);
}

function buildReportScreen() {
    document.getElementById('report-room-id').textContent = appState.roomId || '---';

    // Render report photos
    const photoScroll = document.getElementById('report-photos');
    const photoEmpty  = document.getElementById('report-photos-empty');

    if (appState.photos.length > 0) {
        photoScroll.style.display = 'flex';
        photoEmpty.style.display  = 'none';
        photoScroll.innerHTML = appState.photos.map((p, i) => `
            <img class="report-photo-thumb" src="${escapeHtml(p.localUrl)}" alt="Ảnh ${i+1}">
        `).join('');
    } else {
        photoScroll.style.display = 'none';
        photoEmpty.style.display  = 'flex';
    }

    // Reset voice state
    document.getElementById('voice-transcript').value = appState.voiceText || '';
    setVoiceState('idle');
}

// Voice recording
function setVoiceState(state) {
    const dot    = document.getElementById('voice-status-dot');
    const label  = document.getElementById('voice-status-label');
    const btnMic = document.getElementById('btn-mic');
    const timer  = document.getElementById('voice-timer');

    dot.className = `voice-dot voice-dot--${state}`;

    switch (state) {
        case 'idle':
            label.textContent = 'Nhấn mic để bắt đầu ghi âm';
            btnMic.classList.remove('btn-mic--recording');
            timer.style.display = 'none';
            break;
        case 'ready':
            label.textContent = 'Sẵn sàng ghi âm...';
            btnMic.classList.remove('btn-mic--recording');
            timer.style.display = 'none';
            break;
        case 'rec':
            label.textContent = 'Đang ghi âm — nhấn để dừng';
            btnMic.classList.add('btn-mic--recording');
            timer.style.display = 'block';
            break;
        case 'done':
            label.textContent = 'Đã ghi âm xong — nhấn để ghi lại';
            btnMic.classList.remove('btn-mic--recording');
            timer.style.display = 'none';
            break;
    }
}

function toggleVoiceRecording() {
    if (appState.isRecording) {
        stopVoiceRecording();
    } else {
        startVoiceRecording();
    }
}

function startVoiceRecording() {
    const SpeechRec = window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRec) {
        showToast('Trình duyệt không hỗ trợ ghi âm. Vui lòng nhập tay.', 'warn', 4000);
        return;
    }

    const rec = new SpeechRec();
