    clearInterval(appState.countdownTimer);
    // Clean up state
    appState.photos.forEach(p => URL.revokeObjectURL(p.localUrl));
    appState.photos = [];
    appState.roomId = null;
    appState.voiceText = '';
    appState.qrStarted = false;

    // Reset voice UI
    document.getElementById('voice-transcript').value = '';
    document.getElementById('extra-note').value = '';

    // Reset photo UI
    document.getElementById('photo-thumbnails').innerHTML = '';
    document.getElementById('photo-count').textContent = '0';
    document.getElementById('btn-camera-next').style.display = 'none';
    document.getElementById('btn-camera-next-placeholder').style.display = 'block';

    // Reset QR status
    document.getElementById('qr-status').style.display = 'none';

    navigateBack('screen-qr');

    // Auto-restart QR scanner
    setTimeout(startQRScanner, 600);
}

