rm data as object', '- * @param {HTMLFormElement} form - Form element', '- * @returns {object} Form data', '- */', '-function getFormData(form) {', '-    const formData = new FormData(form);', '-    const data = {};', '-    for (const [key, value] of formData.entries()) {', '-        data[key] = value;', '-    }', '-    return data;', '+function openSuccessScreen(photoCount, hasVoice) {', "+    document.getElementById('success-room-label').textContent =", '+        `Phòng ${appState.roomId} đã được ghi nhận`;', "+    document.getElementById('success-photo-count').textContent = `${photoCount} ảnh`;", "+    document.getElementById('success-voice-status').textContent = hasVoice ? 'Có ghi âm' : 'Không có ghi âm';", "+    document.getElementById('success-time').textContent =", "+        new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' });", '+', "+    navigateTo('screen-success');", '+', '+    // Countdown', '+    let count = 3;', "+    document.getElementById('countdown-num').textContent = count;", '+    clearInterval(appState.countdownTimer);', '+    appState.countdownTimer = setInterval(() => {', '+        count--;', '+        if (count <= 0) {', '+            clearInterval(appState.countdownTimer);', '+            resetToQR();', '+        } else {', "+            document.getElementById('countdown-num').textContent = count;", '+        }', '+    }, 1000);', ' }', '+', '+function resetToQR() {', '+    clearInterval(appState.countdownTimer);', '+    // Clean up state', '+    appState.photos.forEach(p => URL.revokeObjectURL(p.localUrl));', '+    appState.photos = [];', '+    appState.roomId = null;', "+    appState.voiceText = '';", '+    appState.qrStarted = false;', '+', '+    // Reset voice UI', "+    document.getElementById('voice-transcript').value = '';", "+    document.getElementById('extra-note').value = '';", '+', '+    // Reset photo UI', "+    document.getElementById('photo-thumbnails').innerHTML = '';", "+    document.getElementByI