from typing import List, Optional

from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import get_db
from app.schemas.report import ReportCreate, ReportResponse
from app.services.report import create_report, get_reports

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def submit_report(payload: ReportCreate, db: Session = Depends(get_db)):
    """Submit a housekeeping room report with photos and voice text."""
    try:
        report = create_report(db, payload)
        return report
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@router.get("", response_model=List[ReportResponse])
def list_reports(
    room_id: Optional[str] = None,
    limit: int = 50,
    db: Session = Depends(get_db),
):
    """List recent reports, optionally filtered by room_id."""
    return get_reports(db, room_id=room_id, limit=limit)

